const input = items[0].json;
const description = input.ticket.description || "";

// Improved Order ID extraction
const orderIdMatch = description.match(/#?\s*([A-Z]{2,}-\d+|\d{2,})/);
const orderId = orderIdMatch ? orderIdMatch[1] : null;

// Normalize refund reason
let refundReason = "general_refund_request";

if (/damaged/i.test(description)) {
  refundReason = "damaged_item";
} else if (/wrong/i.test(description)) {
  refundReason = "wrong_item";
} else if (/partial/i.test(description)) {
  refundReason = "partial_refund";
} else if (/full/i.test(description)) {
  refundReason = "full_refund";
}

return [
  {
    json: {
      ticket_id: input.ticket.id,
      ticket_subject: input.ticket.subject,
      ticket_status: input.ticket.status,
      ticket_priority: input.ticket.priority,
      ticket_created_at: input.ticket.created_at,
      request_channel: input.ticket.via?.channel || "unknown",
      ticket_tags: input.ticket.tags || [],

      customer_id: input.requester.id,
      customer_name: input.requester.name,
      customer_email: input.requester.email,

      order_id: orderId,
      refund_reason_raw: description,
      refund_type: refundReason,
      source: "zendesk"
    }
  }
];

// Input: WooCommerce Order API response
const order = items[0].json;

// Normalize line items
const normalizedItems = (order.line_items || []).map(item => ({
  product_name: item.name,
  sku: item.sku,
  quantity: item.quantity,
  price: item.price,
  total: parseFloat(item.total)
}));

return [
  {
    json: {
      order_id: order.id,
      order_number: order.number,
      order_status: order.status,

      order_total: parseFloat(order.total),
      currency: order.currency,
      currency_symbol: order.currency_symbol,

      payment_method: order.payment_method || "unknown",
      payment_method_title: order.payment_method_title || "unknown",

      order_created_at: order.date_created,
      order_paid_at: order.date_paid,
      order_completed_at: order.date_completed,

      items: normalizedItems,

      refund_count: order.refunds ? order.refunds.length : 0,
      is_refunded: Array.isArray(order.refunds) && order.refunds.length > 0,

      source: "woocommerce"
    }
  }
];

